changeSet.sql:
COMMENT ON TABLE patient_measure_eligibility_cache IS 'Performance cache for patient measure eligibility computations';
COMMENT ON COLUMN patient_measure_eligibility_cache.patient_data_version IS 'Hash or version of patient data used for eligibility calculation';
COMMENT ON COLUMN patient_measure_eligibility_cache.measure_version IS 'Version of measure definition used for eligibility calculation';
COMMENT ON COLUMN patient_measure_eligibility_cache.valid_until IS 'When this cache entry expires (TTL)';
COMMENT ON COLUMN patient_measure_eligibility_cache.invalidated IS 'Manually invalidated when patient data or measure definition changes';
COMMENT ON COLUMN patient_measure_eligibility_cache.eligibility_criteria_met IS 'JSONB detailing which criteria passed/failed';

CREATE OR REPLACE FUNCTION invalidate_expired_cache_entries()
RETURNS INTEGER AS $function$
DECLARE
    rows_updated INTEGER;
BEGIN
    UPDATE patient_measure_eligibility_cache
    SET invalidated = true
    WHERE invalidated = false
      AND valid_until < CURRENT_TIMESTAMP;

    GET DIAGNOSTICS rows_updated = ROW_COUNT;
    RETURN rows_updated;
END;
$function$ LANGUAGE plpgsql;

COMMENT ON FUNCTION invalidate_expired_cache_entries() IS 'Marks expired cache entries as invalidated. Should be called periodically by scheduled job.';

CREATE OR REPLACE FUNCTION invalidate_patient_eligibility_cache(
    p_patient_id UUID,
    p_measure_id UUID DEFAULT NULL
)
RETURNS INTEGER AS $function$
DECLARE
    rows_updated INTEGER;
BEGIN
    IF p_measure_id IS NULL THEN
        -- Invalidate all measures for this patient
        UPDATE patient_measure_eligibility_cache
        SET invalidated = true
        WHERE patient_id = p_patient_id
          AND invalidated = false;
    ELSE
        -- Invalidate specific measure for this patient
        UPDATE patient_measure_eligibility_cache
        SET invalidated = true
        WHERE patient_id = p_patient_id
          AND measure_id = p_measure_id
          AND invalidated = false;
    END IF;

    GET DIAGNOSTICS rows_updated = ROW_COUNT;
    RETURN rows_updated;
END;
$function$ LANGUAGE plpgsql;

COMMENT ON FUNCTION invalidate_patient_eligibility_cache(UUID, UUID) IS 'Helper function to invalidate patient eligibility cache. Called when patient data or measure definition changes.';
